sql:
SELECT SUM(forest_area_sqkm) AS total_forest_area
FROM forest_area
WHERE year = 2020;

SELECT c.country_name, f.forest_area_sqkm
FROM countries AS c
JOIN forest_area AS f ON c.country_code = f.country_code;

external_knowledge:
- "Forest cover percentage" refers to the percentage of land in a country that is covered by forests;
- "Income group" classifies countries based on their economic status, such as low-income, lower-middle-income, upper-middle-income, and high-income;
- "Region" refers to the geographical area where the country is located, such as North America, Europe, or Asia.

sql:
SELECT country_code, MAX(forest_area_sqkm) AS max_forest_area
FROM forest_area
GROUP BY country_code;

external_knowledge:
- "recent forest areas" refers to the most recent forest area data available for each country based on the year;
- "access statistics" include the total number of access events and the number of download events for each country;
- "income groups" are categorized based on the GDP per capita and other economic indicators;
- "regions" are geographical areas where the countries are located.

sql:
